3611	// Podvm-lifecycle fixture — fetched-side podvm disk-leaf capture against live GAR. Single
3612	// self-contained round-trip: immure a quay.io/podman/machine-os-wsl family into a fresh
3613	// rbi_ld Lode, divine-enumerate to confirm it appears as a cohort, augur to confirm the
3614	// two member tags (rbi_wsl-x86_64, rbi_wsl-aarch64) + decoded :rbi_vouch envelope rode
3615	// in at recorded-at-acquisition grade, jettison one member tag via the type-blind raw
3616	// image verb proving per-member delete, banish the whole Lode, then divine-enumerate to
3617	// confirm the registry is restored. Structural analogue of both reliquary-lifecycle
3618	// (multi-member cohort + member-jettison case) and wsl-lifecycle (opaque-blob capture).
3619	
3620	/// Podvm-wsl kind argument — family brand passed to immure.
3621	const RBTDRC_PODVM_FAMILY: &str = "podvm-wsl";
3622	/// Podvm version tag — the quay.io family index version to capture.
3623	const RBTDRC_PODVM_VERSION: &str = "5.6";
3624	
3625	/// Podvm-wsl member tags asserted by augur. Compose RBGC_LODE_TAG_SPRUE ("rbi_")
3626	/// with the selection leaf names from rbgc_Constants.sh RBGC_LODE_PODVM_WSL_SELECTION.
3627	const RBTDRC_PODVM_TAG_WSL_X86: &str = "rbi_wsl-x86_64";
3628	const RBTDRC_PODVM_TAG_WSL_AARCH: &str = "rbi_wsl-aarch64";
3629	
3630	/// Trust grade for the recorded-at-acquisition envelope — mirrors rbgc_Constants.sh
3631	/// RBGC_LODE_TRUST_RECORDED. The podvm upstream offers no durable checksum, so RB
3632	/// attests only the digest observed at capture.
3633	const RBTDRC_LODE_TRUST_RECORDED: &str = "recorded-at-acquisition";
3634	
3635	/// Honest-posture text fragment emitted by augur for recorded-at-acquisition grade
3636	/// (rbldl_Lifecycle.sh RBGC_LODE_TRUST_RECORDED branch). Proves augur rendered the
3637	/// trust-posture section, not just the envelope header. Matches a stable substring
3638	/// of the fixed prose rather than the full multi-line block.
3639	const RBTDRC_PODVM_TRUST_POSTURE_FRAGMENT: &str = "attests only the digest observed at capture";
