3641	fn rbtdrc_podvm_lifecycle(dir: &Path) -> rbtdre_Verdict {
3642	    rbtdrc_with_ctx(|ctx| {
3643	        // Step 1: immure the podvm-wsl family + version into a fresh Lode.
3644	        let _ = std::fs::write(dir.join("01-immure.txt"), "immuring podvm-wsl disk leaves");
3645	        let immure = match rbtdri_invoke_global(
3646	            ctx,
3647	            RBTDGC_IMMURE_PODVM,
3648	            &[RBTDRC_PODVM_FAMILY, RBTDRC_PODVM_VERSION],
3649	            &[],
3650	        ) {
3651	            Ok(r) if r.exit_code == 0 => r,
3652	            Ok(r) => return rbtdre_Verdict::Fail(format!("immure failed (exit {})\n{}", r.exit_code, r.stderr)),
3653	            Err(e) => return rbtdre_Verdict::Fail(format!("immure invocation: {}", e)),
3654	        };
3655	        let _ = std::fs::write(dir.join("01-immure-stdout.txt"), &immure.stdout);
3656	
3657	        // The host-side capture handoff is the bare touchmark fact.
3658	        let touchmark = match rbtdri_read_burv_fact(&immure, RBTDRC_FACT_LODE_TOUCHMARK) {
3659	            Ok(v) => v,
3660	            Err(e) => return rbtdre_Verdict::Fail(format!("read touchmark fact: {}", e)),
3661	        };
3662	        let _ = std::fs::write(dir.join("02-touchmark.txt"), &touchmark);
3663	
3664	        // Step 2: divine enumerate shows the new Lode as a cohort.
3665	        let after = match rbtdri_invoke_global(ctx, RBTDGC_DIVINE_LODES, &[], &[]) {
3666	            Ok(r) if r.exit_code == 0 => r,
3667	            Ok(r) => return rbtdre_Verdict::Fail(format!("post-immure divine failed (exit {})\n{}", r.exit_code, r.stderr)),
3668	            Err(e) => return rbtdre_Verdict::Fail(format!("post-immure divine invocation: {}", e)),
3669	        };
3670	        let _ = std::fs::write(dir.join("03-divine-after.txt"), &after.stdout);
3671	        if !after.stdout.contains(&touchmark) {
3672	            return rbtdre_Verdict::Fail(format!(
3673	                "post-immure divine missing touchmark {}\nstdout:\n{}",
3674	                touchmark, after.stdout
3675	            ));
3676	        }
3677	        // Cohort display asserts the member count column, not a specific digest.
3678	        if !after.stdout.contains("cohort: 2 members") {
3679	            return rbtdre_Verdict::Fail(format!(
3680	                "post-immure divine row for {} missing '(cohort: 2 members)'\nstdout:\n{}",
3681	                touchmark, after.stdout
3682	            ));
3683	        }
3684	
3685	        // Step 3: augur inspects the podvm Lode — member tags AND the decoded
3686	        // :rbi_vouch envelope. The trust-grade assertion proves augur decoded the
3687	        // recorded-at-acquisition envelope (distinct from the verified grade the bole
3688	        // and reliquary kinds carry); the posture-fragment assertion proves the honest-
3689	        // posture prose block was rendered (struct proof, not digest assertion).
3690	        let augur = match rbtdri_invoke_global(ctx, RBTDGC_AUGUR_LODE, &[&touchmark], &[]) {
3691	            Ok(r) if r.exit_code == 0 => r,
3692	            Ok(r) => return rbtdre_Verdict::Fail(format!("augur failed (exit {})\n{}", r.exit_code, r.stderr)),
3693	            Err(e) => return rbtdre_Verdict::Fail(format!("augur invocation: {}", e)),
3694	        };
3695	        let _ = std::fs::write(dir.join("04-augur.txt"), &augur.stdout);
3696	        // Member-tag presence (structural: these are the two WSL disk-leaf kinds).
3697	        for member in &[RBTDRC_PODVM_TAG_WSL_X86, RBTDRC_PODVM_TAG_WSL_AARCH, RBTDRC_LODE_TAG_VOUCH] {
3698	            if !augur.stdout.contains(member) {
3699	                return rbtdre_Verdict::Fail(format!(
3700	                    "augur missing member tag '{}'\nstdout:\n{}",
3701	                    member, augur.stdout
3702	                ));
3703	            }
3704	        }
3705	        // Trust-grade assertion — recorded-at-acquisition, not verified-against-published.
3706	        // Never assert specific digest hex: the upstream rotates and the digest changes.
3707	        if !augur.stdout.contains(RBTDRC_LODE_TRUST_RECORDED) {
3708	            return rbtdre_Verdict::Fail(format!(
3709	                "augur did not decode podvm :rbi_vouch envelope — missing trust grade '{}'\nstdout:\n{}",
3710	                RBTDRC_LODE_TRUST_RECORDED, augur.stdout
3711	            ));
3712	        }
3713	        // Kind field assertion — proves the envelope names the podvm-wsl kind.
3714	        if !augur.stdout.contains(RBTDRC_PODVM_FAMILY) {
3715	            return rbtdre_Verdict::Fail(format!(
3716	                "augur envelope missing kind '{}'\nstdout:\n{}",
3717	                RBTDRC_PODVM_FAMILY, augur.stdout
3718	            ));
3719	        }
3720	        // Honest-posture prose block — proves the recorded-at-acquisition branch ran.
3721	        if !augur.stdout.contains(RBTDRC_PODVM_TRUST_POSTURE_FRAGMENT) {
3722	            return rbtdre_Verdict::Fail(format!(
3723	                "augur trust-posture prose missing expected fragment '{}'\nstdout:\n{}",
3724	                RBTDRC_PODVM_TRUST_POSTURE_FRAGMENT, augur.stdout
3725	            ));
3726	        }
3727	
3728	        // Step 3.5: per-member jettison via the type-blind raw verbs. The raw
3729	        // list (rbw-il) at leaf grain shows the podvm cohort's member tags; jettison
3730	        // (rbw-iJ) deletes ONE member tag; a re-list proves that member absent and
3731	        // a sibling member still present — the per-member-delete the multi-member
3732	        // podvm kind needs. Tag-grain delete leaves the Lode package and its other
3733	        // members intact (whole-Lode delete stays with banish, below).
3734	        let lode_path = format!("{}/{}", RBTDRC_LODES_ROOT, touchmark);
3735	        let member_ref = format!("{}:{}", lode_path, RBTDRC_PODVM_TAG_WSL_AARCH);
3736	
3737	        let pre_list = match rbtdri_invoke_global(ctx, RBTDGC_LIST_IMAGES, &[&lode_path], &[]) {
3738	            Ok(r) if r.exit_code == 0 => r,
3739	            Ok(r) => return rbtdre_Verdict::Fail(format!("pre-jettison list failed (exit {})\n{}", r.exit_code, r.stderr)),
3740	            Err(e) => return rbtdre_Verdict::Fail(format!("pre-jettison list invocation: {}", e)),
3741	        };
3742	        let _ = std::fs::write(dir.join("04b-list-before-jettison.txt"), &pre_list.stdout);
3743	        for member in &[RBTDRC_PODVM_TAG_WSL_X86, RBTDRC_PODVM_TAG_WSL_AARCH] {
3744	            if !pre_list.stdout.contains(member) {
3745	                return rbtdre_Verdict::Fail(format!(
3746	                    "pre-jettison raw list missing member tag '{}'\nstdout:\n{}",
3747	                    member, pre_list.stdout
3748	                ));
3749	            }
3750	        }
3751	
3752	        let _ = std::fs::write(dir.join("04c-jettison-member.txt"), &member_ref);
3753	        match rbtdri_invoke_global(
3754	            ctx,
3755	            RBTDGC_JETTISON_IMAGE,
3756	            &[&member_ref],
3757	            &[(RBTDRI_BURE_CONFIRM_KEY, RBTDRI_BURE_CONFIRM_SKIP)],
3758	        ) {
3759	            Ok(r) if r.exit_code == 0 => {}
3760	            Ok(r) => return rbtdre_Verdict::Fail(format!("member jettison failed (exit {})\n{}", r.exit_code, r.stderr)),
3761	            Err(e) => return rbtdre_Verdict::Fail(format!("member jettison invocation: {}", e)),
3762	        }
3763	
3764	        let post_list = match rbtdri_invoke_global(ctx, RBTDGC_LIST_IMAGES, &[&lode_path], &[]) {
3765	            Ok(r) if r.exit_code == 0 => r,
3766	            Ok(r) => return rbtdre_Verdict::Fail(format!("post-jettison list failed (exit {})\n{}", r.exit_code, r.stderr)),
3767	            Err(e) => return rbtdre_Verdict::Fail(format!("post-jettison list invocation: {}", e)),
3768	        };
3769	        let _ = std::fs::write(dir.join("04d-list-after-jettison.txt"), &post_list.stdout);
3770	        if post_list.stdout.contains(RBTDRC_PODVM_TAG_WSL_AARCH) {
3771	            return rbtdre_Verdict::Fail(format!(
3772	                "post-jettison list still shows jettisoned member '{}' — member-grain delete failed\nstdout:\n{}",
3773	                RBTDRC_PODVM_TAG_WSL_AARCH, post_list.stdout
3774	            ));
3775	        }
3776	        if !post_list.stdout.contains(RBTDRC_PODVM_TAG_WSL_X86) {
3777	            return rbtdre_Verdict::Fail(format!(
3778	                "post-jettison list missing sibling member '{}' — jettison damaged the Lode\nstdout:\n{}",
3779	                RBTDRC_PODVM_TAG_WSL_X86, post_list.stdout
3780	            ));
3781	        }
3782	
3783	        // Step 4: banish the whole Lode.
3784	        let _ = std::fs::write(dir.join("05-banish.txt"), "banishing");
3785	        match rbtdri_invoke_global(
3786	            ctx,
3787	            RBTDGC_BANISH_LODE,
3788	            &[&touchmark],
3789	            &[(RBTDRI_BURE_CONFIRM_KEY, RBTDRI_BURE_CONFIRM_SKIP)],
3790	        ) {
3791	            Ok(r) if r.exit_code == 0 => {}
3792	            Ok(r) => return rbtdre_Verdict::Fail(format!("banish failed (exit {})\n{}", r.exit_code, r.stderr)),
3793	            Err(e) => return rbtdre_Verdict::Fail(format!("banish invocation: {}", e)),
3794	        }
3795	
3796	        // Step 5: divine enumerate no longer shows the Lode — registry restored.
3797	        let final_divine = match rbtdri_invoke_global(ctx, RBTDGC_DIVINE_LODES, &[], &[]) {
3798	            Ok(r) if r.exit_code == 0 => r,
3799	            Ok(r) => return rbtdre_Verdict::Fail(format!("final divine failed (exit {})\n{}", r.exit_code, r.stderr)),
3800	            Err(e) => return rbtdre_Verdict::Fail(format!("final divine invocation: {}", e)),
3801	        };
3802	        let _ = std::fs::write(dir.join("06-divine-final.txt"), &final_divine.stdout);
3803	        if final_divine.stdout.contains(&touchmark) {
3804	            return rbtdre_Verdict::Fail(format!(
3805	                "final divine still shows banished touchmark {} — banish did not restore baseline\nstdout:\n{}",
3806	                touchmark, final_divine.stdout
3807	            ));
3808	        }
3809	
3810	        let _ = std::fs::write(dir.join("07-passed.txt"), "passed");
3811	        rbtdre_Verdict::Pass
3812	    })
3813	}
