93	
94	fn rbtdb_run_fixture(args: &[String]) -> ExitCode {
95	    let fixture = match args.first() {
96	        Some(n) => n,
97	        None => rbtd::rbtdrg_fatal_now!(
98	            "rbtd: usage: rbtd <fixture>\n\
99	             theurge must be launched via tabtarget (e.g. tt/rbw-tf.FixtureRun.sh tadmor)"
100	        ),
101	    };
102	
103	    let project_root = match std::env::current_dir() {
104	        Ok(p) => p,
105	        Err(e) => rbtd::rbtdrg_fatal_now!("rbtd: cannot determine working directory: {}", e),
106	    };
107	
108	    // Run-start hygiene guard (suite only). A suite run commits a sequence of
109	    // hallmark/yoke changes; starting on a dirty tree would interleave the
110	    // operator's uncommitted edits with those commits. Single-case mode is the
111	    // crucible-debug loop and is intentionally left unguarded.
112	    if let Err(msg) = rbtdre_tree_clean(&project_root) {
113	        rbtd::rbtdrg_fatal_now!(
114	            "rbtd: refusing to start a suite run on a dirty working tree — \
115	             commit or stash first.\n{}",
116	            msg
117	        );
118	    }
119	
120	    let roots = match rbtdb_allocate_roots() {
121	        Ok(r) => r,
122	        Err(msg) => rbtd::rbtdrg_fatal_now!("{}", msg),
123	    };
124	
125	    let ctx = rbtdri_Context::new(
126	        &project_root,
127	        fixture,
128	        &roots.burv_temp_root,
129	        &roots.burv_output_root,
130	    );
131	
132	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
133	        Some(f) => f,
134	        None => rbtd::rbtdrg_fatal_now!(
135	            "rbtd: fixture '{}' has no registered Fixture — \
136	             no Fixture static is bound. \
137	             Update rbtdrc_lookup_fixture in rbtdrc_crucible.rs.",
138	            fixture
139	        ),
140	    };
141	
142	    rbtdrc_set_context(ctx);
143	
144	    let colors = rbtdre_detect_colors();
145	    let run_result = rbtdre_run_fixture(fixture_def, &colors, &roots.trace_root);
146	
147	    let _ctx = rbtdrc_take_context();
148	
149	    let result = match run_result {
150	        Ok(r) => r,
151	        Err(msg) => rbtd::rbtdrg_fatal_now!("rbtd: {}", msg),
152	    };
153	
154	    rbtdre_print_summary(&result, &colors);
155	
156	    if result.failed > 0 {
157	        rbtd::rbtdrg_error_now!("rbtd: {} case(s) failed", result.failed);
158	        ExitCode::FAILURE
159	    } else {
160	        ExitCode::SUCCESS
161	    }
162	}
