285	fn rbtdb_run_single(args: &[String]) -> ExitCode {
286	    let fixture = match args.first() {
287	        Some(f) => f,
288	        None => {
289	            rbtd::rbtdrg_error_now!(
290	                "rbtd single: usage: rbtd single <fixture> [case]\n\
291	                 omit case to list all cases for the fixture"
292	            );
293	            rbtdb_list_fixtures();
294	            return ExitCode::FAILURE;
295	        }
296	    };
297	
298	    if !RBTDRC_FIXTURES.iter().any(|f| f.name == *fixture) {
299	        rbtd::rbtdrg_error_now!("rbtd single: unknown fixture '{}'", fixture);
300	        rbtdb_list_fixtures();
301	        return ExitCode::FAILURE;
302	    }
303	
304	    // Set up execution context early — needed for charge check and case execution
305	    let project_root = match std::env::current_dir() {
306	        Ok(p) => p,
307	        Err(e) => rbtd::rbtdrg_fatal_now!("rbtd: cannot determine working directory: {}", e),
308	    };
309	
310	    let roots = match rbtdb_allocate_roots() {
311	        Ok(r) => r,
312	        Err(msg) => rbtd::rbtdrg_fatal_now!("{}", msg),
313	    };
314	
315	    // Context is required for every case execution path (rbtdrc_with_ctx).
316	    // Fixtures with a setup hook (crucible charge) additionally verify their
317	    // crucible is charged externally — single-case mode never charges.
318	    let mut ctx = rbtdri_Context::new(
319	        &project_root,
320	        fixture,
321	        &roots.burv_temp_root,
322	        &roots.burv_output_root,
323	    );
324	
325	    let fixture_def = match rbtdrc_lookup_fixture(fixture) {
326	        Some(f) => f,
327	        None => rbtd::rbtdrg_fatal_now!(
328	            "rbtd single: fixture '{}' has no registered Fixture",
329	            fixture
330	        ),
331	    };
332	
333	    if fixture_def.setup.is_some() {
334	        match rbtdri_invoke_global(
335	            &mut ctx,
336	            RBTDGC_CRUCIBLE_ACTIVE,
337	            &[fixture],
338	            &[],
339	        ) {
340	            Ok(r) if r.exit_code == 0 => {}
